const CHECKOUT_STORAGE_KEY = 'tienda_react_checkout_form';
const ORDERS_STORAGE_KEY = 'tienda_react_orders';

/**
 * Reads persisted checkout form values safely.
 * @returns {{ name: string, email: string, address: string, city: string, zip: string, card: string }}
 */
function getInitialCheckoutForm() {
  const fallback = {
    name: '',
    email: '',
    address: '',
    city: '',
    zip: '',
    card: '',
  };

  try {
    const rawForm = localStorage.getItem(CHECKOUT_STORAGE_KEY);
    if (!rawForm) {
      return fallback;
    }

    const parsed = JSON.parse(rawForm);
    return {
      ...fallback,
      ...parsed,
      // Never restore sensitive payment fields from persistent storage.
      card: '',
    };
  } catch {
    return fallback;
  }
}

/**
 * Basic Luhn validation to reduce malformed card input before submission.
 * @param {string} cardNumber
 * @returns {boolean}
 */
function isValidCardLuhn(cardNumber) {
  let sum = 0;
  let shouldDouble = false;

  for (let i = cardNumber.length - 1; i >= 0; i -= 1) {
    let digit = Number.parseInt(cardNumber[i], 10);
    if (Number.isNaN(digit)) {
      return false;
    }

    if (shouldDouble) {
      digit *= 2;
      if (digit > 9) {
        digit -= 9;
      }
    }

    sum += digit;
    shouldDouble = !shouldDouble;
  }

  return sum % 10 === 0;
}

/** Formats card digits into groups of four for readability. */
function formatCardNumber(value) {
  const digits = String(value || '').replace(/\D/g, '').slice(0, 16);
  return digits.replace(/(\d{4})(?=\d)/g, '$1 ');
}

/**
 * Saves a completed order to local history.
 * @param {{ name: string }} formData
 * @param {Array<{ id: number|string, name: string, quantity: number, price: number }>} items
 * @param {number} total
 */
function persistOrder(formData, items, subtotal, discountAmount, finalPrice, coupon) {
  const newOrder = {
    id: `${Date.now()}`,
    createdAt: new Date().toISOString(),
    customerName: formData.name.trim(),
    totalItems: items.reduce((sum, item) => sum + item.quantity, 0),
    subtotalPrice: subtotal,
    discountAmount,
    couponCode: coupon?.code ?? null,
    totalPrice: finalPrice,
    items: items.map((item) => ({
      id: item.id,
      name: item.name,
      quantity: item.quantity,
      price: item.price,
      image: item.image,
    })),
  };

  try {
    const rawOrders = localStorage.getItem(ORDERS_STORAGE_KEY);
    const currentOrders = rawOrders ? JSON.parse(rawOrders) : [];
    const safeOrders = Array.isArray(currentOrders) ? currentOrders : [];
    localStorage.setItem(ORDERS_STORAGE_KEY, JSON.stringify([newOrder, ...safeOrders]));
  } catch {
    localStorage.setItem(ORDERS_STORAGE_KEY, JSON.stringify([newOrder]));
  }
}

/**
 * Reusable field used by checkout form sections.
 */
function CheckoutField({
  id,
  label,
  type = 'text',
  name,
  placeholder,
  autoComplete,
  inputMode,
  maxLength,
  value,
  hasError,
  errorMessage,
  onChange,
  onBlur,
}) {
  return (
    <div className="flex flex-col gap-1">
      <label htmlFor={id} className="text-sm font-medium text-gray-700">
        {label}
      </label>
      <input
        id={id}
        type={type}
        name={name}
        value={value}
        onChange={onChange}
        onBlur={onBlur}
        placeholder={placeholder}
        autoComplete={autoComplete}
        inputMode={inputMode}
        maxLength={maxLength}
        className={`border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 transition ${
          hasError ? 'border-red-400' : 'border-gray-300'
        }`}
        aria-invalid={hasError}
        aria-describedby={hasError ? `${id}-error` : undefined}
      />
      {hasError && (
        <span id={`${id}-error`} className="text-red-500 text-xs" role="alert">
          {errorMessage}
        </span>
      )}
    </div>
  );
}

